+            w.stackPred = (int)pc;
+            qac = (qc = (pc - RC_UNIT) & UMASK | (activePhase & LMASK)) & RC_MASK;
+            if (pc == (pc = U.compareAndExchangeLong(this, CTL, pc, qc)))
+                break;
+            else if (qac < (pc & RC_MASK))
